import { Music, Sun, Volume2, X } from 'lucide-react';
import React, { useMemo } from 'react';
import { GameSettings } from '../types';

interface SettingsScreenProps {
  settings: GameSettings;
  onUpdateSetting: (key: keyof GameSettings, value: number) => void;
  onClose: () => void;
  playSfx: () => void;
}

export const SettingsScreen: React.FC<SettingsScreenProps> = ({ settings, onUpdateSetting, onClose, playSfx }) => {
  const handleSliderChange = (key: keyof GameSettings, e: React.ChangeEvent<HTMLInputElement>) => {
    const value = parseFloat(e.target.value);
    onUpdateSetting(key, value);
  };

  const handleDragEnd = () => {
    playSfx();
  };

  return (
    <div className="game-modal absolute inset-0 z-[60] bg-black/50 backdrop-blur-md flex items-center justify-center p-4 animate-in fade-in duration-300">
      <div className="w-full max-w-md h-auto glass-panel border border-white/10 shadow-[0_20px_60px_rgba(0,0,0,0.8)] relative overflow-hidden flex flex-col rounded-xl">
        {/* 背景光效 */}
        <div className="absolute top-0 right-0 w-64 h-64 bg-[radial-gradient(circle_at_top_right,rgba(255,255,255,0.05),transparent_70%)] pointer-events-none" />

        {/* Header */}
        <div className="flex justify-between items-center px-8 py-6 border-b border-white/5 bg-gradient-to-b from-white/[0.03] to-transparent">
          <div className="flex flex-col gap-1">
            <h2 className="font-serif-sc text-xl text-white tracking-[0.1em] font-medium drop-shadow-md">SETTINGS</h2>
            <span className="font-mono-retro text-[9px] text-stone-400 tracking-[0.3em] uppercase ml-1">
              system_config
            </span>
          </div>
          <button
            onClick={() => {
              playSfx();
              onClose();
            }}
            className="w-8 h-8 flex items-center justify-center bg-white/5 border border-white/10 rounded-full text-stone-400 hover:text-white hover:bg-white/15 transition-all duration-300 cursor-pointer group"
            onMouseEnter={playSfx}
          >
            <X size={14} className="group-hover:rotate-90 transition-transform duration-300" />
          </button>
        </div>

        {/* Body */}
        <div className="px-8 py-8 flex flex-col gap-6 overflow-y-auto">
          {/* SFX Volume */}
          <ControlRow
            icon={<Volume2 size={16} />}
            label="SFX VOLUME"
            value={settings.volumeSfx}
            max={1}
            step={0.1}
            onChange={e => handleSliderChange('volumeSfx', e)}
            onDragEnd={handleDragEnd}
            displayValue={`${Math.round(settings.volumeSfx * 100)}%`}
            accentColor="#ef4444"
          />

          <div className="h-px bg-gradient-to-r from-transparent via-white/10 to-transparent" />

          {/* Music Volume */}
          <ControlRow
            icon={<Music size={16} />}
            label="BGM VOLUME"
            value={settings.volumeMusic}
            max={1}
            step={0.1}
            onChange={e => handleSliderChange('volumeMusic', e)}
            onDragEnd={handleDragEnd}
            displayValue={`${Math.round(settings.volumeMusic * 100)}%`}
            accentColor="#a855f7"
          />

          <div className="h-px bg-gradient-to-r from-transparent via-white/10 to-transparent" />

          {/* Brightness */}
          <ControlRow
            icon={<Sun size={16} />}
            label="BRIGHTNESS"
            value={settings.brightness}
            max={100}
            step={5}
            onChange={e => handleSliderChange('brightness', e)}
            onDragEnd={handleDragEnd}
            displayValue={`${Math.round(settings.brightness)}%`}
            accentColor="#eab308"
          />
        </div>

        {/* 底部信息 */}
        <div className="px-8 py-4 border-t border-white/5 bg-black/20 flex justify-between items-center">
          <span className="text-[10px] font-mono-retro text-stone-500 tracking-[0.2em]">WASTELAND_ECHOES</span>
          <span className="text-[9px] font-mono-retro text-stone-600 tracking-wider">v1.2.0</span>
        </div>
      </div>
    </div>
  );
};

interface ControlRowProps {
  icon: React.ReactNode;
  label: string;
  value: number;
  max: number;
  step: number;
  onChange: (e: React.ChangeEvent<HTMLInputElement>) => void;
  onDragEnd: () => void;
  displayValue: string;
  accentColor?: string;
}

const ControlRow: React.FC<ControlRowProps> = ({
  icon,
  label,
  value,
  max,
  step,
  onChange,
  onDragEnd,
  displayValue,
  accentColor = '#ffffff',
}) => {
  const fillPercent = useMemo(() => (value / max) * 100, [value, max]);

  return (
    <div className="flex flex-col gap-3 group">
      <div className="flex justify-between items-end">
        <div className="flex items-center gap-3 text-stone-400 group-hover:text-stone-300 transition-colors">
          <div className="opacity-70 group-hover:opacity-100 transition-opacity">{icon}</div>
          <span className="font-mono-retro text-[11px] tracking-[0.2em]">{label}</span>
        </div>
        <span className="font-mono-retro text-white text-sm tabular-nums min-w-[3em] text-right drop-shadow-[0_0_8px_rgba(255,255,255,0.3)]">
          {displayValue}
        </span>
      </div>
      <div className="relative h-1.5 bg-black/40 rounded-full overflow-hidden border border-white/5">
        {/* Track fill */}
        <div
          className="absolute top-0 left-0 h-full transition-all duration-150 ease-out"
          style={{ width: `${fillPercent}%`, backgroundColor: accentColor, boxShadow: `0 0 10px ${accentColor}` }}
        />
        {/* Invisible range input overlaid on top */}
        <input
          type="range"
          min="0"
          max={max}
          step={step}
          value={value}
          onChange={onChange}
          onMouseUp={onDragEnd}
          onTouchEnd={onDragEnd}
          className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
        />
      </div>
    </div>
  );
};
