import {
  BookOpen,
  Check,
  ChevronLeft,
  ChevronRight,
  Dice5,
  FastForward,
  FolderOpen,
  Fullscreen,
  Heart,
  History,
  Loader2,
  Menu,
  Minimize2,
  Play,
  Rewind,
  Settings,
  User,
  X,
} from 'lucide-react';
import React, { useCallback, useEffect, useState } from 'react';
import { GameSettings } from '../types';

// ====== 纯图标按钮（常驻栏用）======
const TopIconButton: React.FC<{
  icon: React.ReactNode;
  title: string;
  onClick: () => void;
  playSfx: () => void;
  active?: boolean;
}> = ({ icon, title, onClick, playSfx, active }) => (
  <button
    title={title}
    onClick={e => {
      e.stopPropagation();
      playSfx();
      onClick();
    }}
    className={`
      flex items-center justify-center w-11 h-11 rounded-full
      transition-all duration-300 cursor-pointer overflow-hidden relative
      ${
        active
          ? 'bg-white/10 backdrop-blur-md border border-white/30 text-white shadow-[0_0_15px_rgba(255,255,255,0.2)]'
          : 'bg-black/30 backdrop-blur-md border border-white/10 text-stone-300 hover:bg-white/15 hover:text-white hover:border-white/40 hover:shadow-[0_0_20px_rgba(255,255,255,0.15)] hover:-translate-y-0.5'
      }
    `}
  >
    {/* Hover 发光背景 */}
    <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,rgba(255,255,255,0.15),transparent_70%)] opacity-0 hover:opacity-100 transition-opacity duration-300" />
    <span className="relative z-10 drop-shadow-md">{icon}</span>
  </button>
);

// ====== 抽屉内网格按钮 ======
const DrawerButton: React.FC<{
  icon: React.ReactNode;
  label: string;
  onClick: () => void;
  playSfx: () => void;
  active?: boolean;
  loading?: boolean;
  index: number;
}> = ({ icon, label, onClick, playSfx, active, loading, index }) => (
  <button
    onClick={e => {
      e.stopPropagation();
      playSfx();
      onClick();
    }}
    className={`
      group flex flex-col items-center justify-center gap-2.5 py-4 rounded-md relative overflow-hidden
      transition-all duration-300 ease-[cubic-bezier(0.16,1,0.3,1)] cursor-pointer
      ${
        active
          ? 'bg-white/10 border border-white/20 text-white shadow-[0_0_15px_rgba(255,255,255,0.1)]'
          : 'bg-black/20 border border-white/5 text-stone-400 hover:bg-white/[0.08] hover:text-white hover:border-white/20 hover:-translate-y-1'
      }
    `}
    style={{
      animation: `fade-in 0.4s ease-out forwards`,
      animationDelay: `${index * 40}ms`,
      opacity: 0,
      transform: 'translateY(10px)',
    }}
  >
    {/* Hover 背景光 */}
    <div className="absolute inset-0 bg-gradient-to-b from-white/0 to-white/5 opacity-0 group-hover:opacity-100 transition-opacity duration-300" />

    <div className="relative z-10 transition-transform duration-300 group-hover:scale-110 drop-shadow-md">
      {loading ? <Loader2 size={18} className="animate-spin text-white/70" /> : icon}
    </div>
    <span className="relative z-10 text-[9px] font-mono-retro tracking-[0.2em] uppercase font-bold group-hover:tracking-[0.25em] transition-all duration-300">
      {label}
    </span>
  </button>
);

// ====== 侧边抽屉 ======
const SideDrawer: React.FC<{
  isOpen: boolean;
  onClose: () => void;
  children: React.ReactNode;
}> = ({ isOpen, onClose, children }) => {
  const [mounted, setMounted] = useState(false);
  const [visible, setVisible] = useState(false);

  useEffect(() => {
    if (isOpen) {
      setMounted(true);
      requestAnimationFrame(() => {
        requestAnimationFrame(() => setVisible(true));
      });
      return;
    } else {
      setVisible(false);
      const timer = setTimeout(() => setMounted(false), 350);
      return () => clearTimeout(timer);
    }
  }, [isOpen]);

  if (!mounted) return null;

  return (
    <div className="absolute inset-0 z-[35]">
      {/* 遮罩 */}
      <div
        className={`absolute inset-0 transition-all duration-350
          ${visible ? 'bg-black/50' : 'bg-transparent'}
        `}
        onClick={onClose}
      />
      {/* 抽屉面板 - 高级半透明材质 */}
      <div
        className={`
          game-side-drawer absolute top-0 right-0 h-full w-64
          bg-gradient-to-bl from-[rgba(15,15,18,0.7)] to-[rgba(5,5,5,0.9)]
          backdrop-blur-xl border-l border-white/10 shadow-[-10px_0_30px_rgba(0,0,0,0.5)]
          flex flex-col
          transition-all duration-[400ms] ease-[cubic-bezier(0.16,1,0.3,1)]
          ${visible ? 'translate-x-0 opacity-100' : 'translate-x-full opacity-0'}
        `}
      >
        {/* 背景装饰光晕 */}
        <div className="absolute top-0 right-0 w-full h-1/3 bg-[radial-gradient(ellipse_at_top_right,rgba(255,255,255,0.05),transparent_70%)] pointer-events-none" />

        {/* 左侧装饰切线 */}
        <div className="absolute top-0 left-0 w-[1px] h-full bg-gradient-to-b from-white/30 via-white/5 to-transparent" />

        {/* 标题栏 */}
        <div className="relative flex items-center justify-between px-6 pt-8 pb-4">
          <div className="flex flex-col gap-1">
            <div className="flex items-center gap-2">
              <div className="relative flex items-center justify-center w-3 h-3">
                <div className="w-1.5 h-1.5 bg-white rounded-full shadow-[0_0_8px_rgba(255,255,255,0.8)]" />
                <div
                  className="absolute inset-0 border border-white/30 rounded-full animate-ping"
                  style={{ animationDuration: '3s' }}
                />
              </div>
              <span className="font-serif-sc text-sm text-white tracking-[0.2em] font-medium drop-shadow-md">
                SYSTEM
              </span>
            </div>
            <span className="font-mono-retro text-[8px] text-white/40 tracking-[0.4em] uppercase ml-5">
              control_nexus
            </span>
          </div>

          <button
            onClick={onClose}
            className="group w-8 h-8 flex items-center justify-center bg-white/5 border border-white/10 rounded-full text-stone-400 hover:text-white hover:bg-white/15 hover:border-white/30 transition-all duration-300 cursor-pointer shadow-[0_0_10px_rgba(0,0,0,0.2)] hover:rotate-90"
          >
            <X size={14} />
          </button>
        </div>

        {/* 分隔线 */}
        <div className="mx-6 h-px bg-gradient-to-r from-white/20 via-white/5 to-transparent relative">
          <div className="absolute left-0 top-1/2 -translate-y-1/2 w-8 h-[2px] bg-white/40" />
        </div>

        {/* 按钮网格 */}
        <div className="flex-1 overflow-y-auto px-5 py-6 scrollbar-thin scrollbar-thumb-white/10 scrollbar-track-transparent">
          <div className="grid grid-cols-2 gap-3">{children}</div>
        </div>

        {/* 底部装饰 */}
        <div className="mx-6 h-px bg-gradient-to-r from-transparent via-white/10 to-transparent relative">
          <div className="absolute right-0 top-1/2 -translate-y-1/2 w-4 h-px bg-white/30" />
        </div>
        <div className="px-6 py-5 flex items-center justify-between">
          <div className="flex flex-col gap-0.5">
            <span className="font-serif-sc text-[10px] text-white/50 tracking-[0.1em] uppercase drop-shadow-sm">
              wasteland-echoes
            </span>
            <span className="font-mono-retro text-[7px] text-white/30 tracking-[0.3em] uppercase">v1.0.0</span>
          </div>
          <div className="flex gap-1 opacity-60">
            <div className="w-1 h-3 bg-white/20 rounded-full" />
            <div className="w-1 h-3 bg-white/40 rounded-full" />
            <div className="w-1 h-3 bg-white/80 rounded-full shadow-[0_0_4px_rgba(255,255,255,0.5)]" />
          </div>
        </div>
      </div>
    </div>
  );
};

// ====== 主组件 ======
interface TopControlBarProps {
  settings: GameSettings;
  onToggleSetting: (setting: keyof GameSettings) => void;
  onShowLog: () => void;
  onShowStatus: () => void;
  onShowSettings: () => void;
  onShowSaveLoad: () => void;
  onShowCollection: () => void;
  onShowRelationship: () => void;
  onToggleFullscreen: () => void;
  isFullscreen: boolean;
  playSfx: () => void;
  onBack: () => void;
  onRoll: () => void;
  isRolling: boolean;
  currentSwipeId: number;
  totalSwipes: number;
  onSwipeNav: (direction: 'prev' | 'next') => void;
  onCommitRoll: () => Promise<void>;
}

export const TopControlBar: React.FC<TopControlBarProps> = ({
  settings,
  onToggleSetting,
  onShowLog,
  onShowStatus,
  onShowSettings,
  onShowSaveLoad,
  onShowCollection,
  onShowRelationship,
  onToggleFullscreen,
  isFullscreen,
  playSfx,
  onBack,
  onRoll,
  isRolling,
  currentSwipeId,
  totalSwipes,
  onSwipeNav,
  onCommitRoll,
}) => {
  const [drawerOpen, setDrawerOpen] = useState(false);

  const withDrawerClose = useCallback((fn: () => void) => {
    return () => {
      fn();
      setDrawerOpen(false);
    };
  }, []);

  const stopPropagation = useCallback((e: React.MouseEvent) => {
    e.stopPropagation();
  }, []);

  return (
    <>
      {/* 常驻按钮栏 */}
      <div
        className="game-top-controls absolute top-6 right-8 z-30 flex items-center gap-2.5"
        onClick={stopPropagation}
      >
        {/* BACK */}
        <TopIconButton icon={<Rewind size={18} />} title="回退 (BACK)" onClick={onBack} playSfx={playSfx} />

        {/* Swipe 导航器（条件显示）— 半透明高级胶囊条 */}
        {totalSwipes > 1 && (
          <div className="flex items-center h-11 rounded-full border border-white/10 bg-black/30 backdrop-blur-md overflow-hidden shadow-[0_0_15px_rgba(0,0,0,0.3)]">
            <button
              onClick={() => {
                playSfx();
                onSwipeNav('prev');
              }}
              disabled={currentSwipeId <= 0}
              className="h-full px-3 flex items-center justify-center text-stone-300 hover:text-white hover:bg-white/10 disabled:opacity-30 disabled:cursor-not-allowed transition-all duration-200 cursor-pointer"
            >
              <ChevronLeft size={16} />
            </button>

            <div className="h-4 w-px bg-white/20 mx-1" />

            <span className="font-mono-retro text-[11px] text-white/80 tracking-widest px-3 select-none flex gap-1 items-center font-bold">
              <span className="text-white">{currentSwipeId + 1}</span>
              <span className="opacity-50">/</span>
              <span className="opacity-70">{totalSwipes}</span>
            </span>

            <div className="h-4 w-px bg-white/20 mx-1" />

            <button
              onClick={() => {
                playSfx();
                onSwipeNav('next');
              }}
              disabled={currentSwipeId >= totalSwipes - 1}
              className="h-full px-3 flex items-center justify-center text-stone-300 hover:text-white hover:bg-white/10 disabled:opacity-30 disabled:cursor-not-allowed transition-all duration-200 cursor-pointer"
            >
              <ChevronRight size={16} />
            </button>

            <div className="h-full w-px bg-gradient-to-b from-transparent via-white/30 to-transparent" />

            <button
              onClick={() => {
                playSfx();
                onCommitRoll();
              }}
              title="确认选用当前结果"
              className="h-full px-4 flex items-center justify-center text-white/70 hover:text-white hover:bg-white/10 hover:shadow-[inset_0_0_10px_rgba(255,255,255,0.2)] transition-all duration-200 cursor-pointer relative group"
            >
              <Check size={16} className="group-hover:scale-110 transition-transform" />
            </button>
          </div>
        )}

        {/* 菜单触发按钮 */}
        <TopIconButton
          icon={<Menu size={18} />}
          title="菜单 (MENU)"
          onClick={() => setDrawerOpen(true)}
          playSfx={playSfx}
        />
      </div>

      {/* 侧边抽屉 */}
      <SideDrawer
        isOpen={drawerOpen}
        onClose={() => {
          playSfx();
          setDrawerOpen(false);
        }}
      >
        <DrawerButton
          index={0}
          icon={<Dice5 size={18} strokeWidth={1.5} />}
          label="ROLL"
          onClick={withDrawerClose(onRoll)}
          playSfx={playSfx}
          loading={isRolling}
        />
        <DrawerButton
          index={1}
          icon={<History size={18} strokeWidth={1.5} />}
          label="LOG"
          onClick={withDrawerClose(onShowLog)}
          playSfx={playSfx}
        />
        <DrawerButton
          index={2}
          icon={<Play size={18} strokeWidth={1.5} />}
          label="AUTO"
          onClick={withDrawerClose(() => onToggleSetting('autoPlay'))}
          playSfx={playSfx}
          active={settings.autoPlay}
        />
        <DrawerButton
          index={3}
          icon={<FastForward size={18} strokeWidth={1.5} />}
          label="3x"
          onClick={withDrawerClose(() => onToggleSetting('speed'))}
          playSfx={playSfx}
          active={settings.speed === 2}
        />
        <DrawerButton
          index={4}
          icon={<User size={18} strokeWidth={1.5} />}
          label="STATUS"
          onClick={withDrawerClose(onShowStatus)}
          playSfx={playSfx}
        />
        <DrawerButton
          index={5}
          icon={<FolderOpen size={18} strokeWidth={1.5} />}
          label="LOAD"
          onClick={withDrawerClose(onShowSaveLoad)}
          playSfx={playSfx}
        />
        <DrawerButton
          index={6}
          icon={<Heart size={18} strokeWidth={1.5} />}
          label="BOND"
          onClick={withDrawerClose(onShowRelationship)}
          playSfx={playSfx}
        />
        <DrawerButton
          index={7}
          icon={<BookOpen size={18} strokeWidth={1.5} />}
          label="ARCHIVE"
          onClick={withDrawerClose(onShowCollection)}
          playSfx={playSfx}
        />
        <DrawerButton
          index={8}
          icon={<Settings size={18} strokeWidth={1.5} />}
          label="SYSTEM"
          onClick={withDrawerClose(onShowSettings)}
          playSfx={playSfx}
        />
        <DrawerButton
          index={9}
          icon={isFullscreen ? <Minimize2 size={18} strokeWidth={1.5} /> : <Fullscreen size={18} strokeWidth={1.5} />}
          label={isFullscreen ? 'WIND' : 'FULL'}
          onClick={withDrawerClose(onToggleFullscreen)}
          playSfx={playSfx}
        />
      </SideDrawer>
    </>
  );
};
