import { Skull, Trash2, X } from 'lucide-react';
import React, { useCallback, useEffect, useState } from 'react';

interface EndingItem {
  标题: string;
  描述: string;
}

interface CollectionScreenProps {
  onClose: () => void;
  playSfx: () => void;
}

/** 从角色卡变量读取已解锁的结局列表 */
function loadEndingsFromCharVar(): EndingItem[] {
  try {
    const charVars = getVariables({ type: 'character' }) as Record<string, any>;
    const endings: EndingItem[] = charVars?.收集?.结局 ?? [];
    return Array.isArray(endings) ? endings : [];
  } catch (e) {
    console.warn('[CollectionScreen] 读取角色卡变量失败:', e);
    return [];
  }
}

/** 从角色卡变量中删除指定结局 */
function removeEndingFromCharVar(title: string): EndingItem[] {
  try {
    const charVars = getVariables({ type: 'character' }) as Record<string, any>;
    const endings: EndingItem[] = charVars?.收集?.结局 ?? [];
    const filtered = endings.filter(e => e.标题 !== title);
    replaceVariables({ ...charVars, 收集: { ...(charVars.收集 || {}), 结局: filtered } }, { type: 'character' });
    console.info(`[CollectionScreen] 已删除结局: ${title}`);
    return filtered;
  } catch (e) {
    console.error('[CollectionScreen] 删除结局失败:', e);
    return [];
  }
}

export const CollectionScreen: React.FC<CollectionScreenProps> = ({ onClose, playSfx }) => {
  const [endings, setEndings] = useState<EndingItem[]>([]);
  const [confirmDelete, setConfirmDelete] = useState<string | null>(null);

  useEffect(() => {
    setEndings(loadEndingsFromCharVar());
  }, []);

  const handleDelete = useCallback(
    (title: string) => {
      playSfx();
      const updated = removeEndingFromCharVar(title);
      setEndings(updated);
      setConfirmDelete(null);
    },
    [playSfx],
  );

  return (
    <div className="absolute inset-0 z-40 flex flex-col bg-gradient-to-b from-[rgba(10,10,12,0.95)] to-black backdrop-blur-md">
      {/* 背景光晕 */}
      <div className="absolute top-[-10%] right-[-5%] w-[40%] h-[40%] bg-amber-900/10 blur-[100px] pointer-events-none" />

      {/* 顶部标题栏 */}
      <div className="relative flex items-center justify-between px-8 pt-8 pb-5 z-10">
        <div className="flex flex-col gap-1">
          <div className="flex items-center gap-3">
            <span className="w-1.5 h-1.5 bg-amber-500 rounded-full shadow-[0_0_8px_rgba(245,158,11,0.8)] animate-pulse" />
            <h2 className="font-serif-sc text-xl text-white tracking-[0.15em] font-medium drop-shadow-md">
              COLLECTION
            </h2>
          </div>
          <span className="font-mono-retro text-[9px] text-stone-400 tracking-[0.4em] uppercase ml-4.5">
            archive_nexus
          </span>
        </div>
        <button
          onClick={() => {
            playSfx();
            onClose();
          }}
          className="w-10 h-10 flex items-center justify-center rounded-full bg-white/5 border border-white/10 text-stone-400 hover:text-white hover:bg-white/15 transition-all duration-300 cursor-pointer shadow-[0_0_15px_rgba(0,0,0,0.2)] group"
        >
          <X size={16} className="group-hover:rotate-90 transition-transform duration-300" />
        </button>
      </div>

      {/* 分隔线 */}
      <div className="mx-8 h-px bg-gradient-to-r from-amber-600/50 via-white/10 to-transparent relative">
        <div className="absolute left-0 top-1/2 -translate-y-1/2 w-12 h-[2px] bg-amber-500/80 shadow-[0_0_8px_rgba(245,158,11,0.5)]" />
      </div>

      {/* Tab 区域（目前只有结局，预留扩展） */}
      <div className="px-8 pt-6 pb-2 flex items-center gap-6">
        <button className="flex flex-col items-start gap-1 group cursor-pointer relative pb-2">
          <span className="font-mono-retro text-[10px] tracking-[0.25em] uppercase text-white group-hover:text-white transition-colors">
            ENDINGS
          </span>
          <div className="absolute bottom-0 left-0 w-full h-[2px] bg-white shadow-[0_0_8px_rgba(255,255,255,0.8)]" />
        </button>
        <button className="flex flex-col items-start gap-1 group cursor-pointer relative pb-2 opacity-30 hover:opacity-80 transition-opacity">
          <span className="font-mono-retro text-[10px] tracking-[0.25em] uppercase text-stone-400">[LOCKED]</span>
          <div className="absolute bottom-0 left-0 w-0 h-[2px] bg-white transition-all group-hover:w-full" />
        </button>
      </div>

      {/* 结局列表 (网格布局) */}
      <div className="flex-1 overflow-y-auto px-8 py-6 custom-scrollbar relative z-10">
        {endings.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-full gap-4 text-stone-500 opacity-60">
            <Skull size={36} className="text-stone-600 opacity-50 mb-2" strokeWidth={1.5} />
            <p className="font-mono-retro text-xs tracking-[0.3em] uppercase">EMPTY_ARCHIVE</p>
            <p className="font-serif-sc text-[13px] text-stone-500 tracking-wider">尚未解锁任何记忆残片</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4 auto-rows-max">
            {endings.map((ending, idx) => (
              <div
                key={`${ending.标题}_${idx}`}
                className="group relative glass-panel border border-white/5 rounded-lg overflow-hidden transition-all duration-500 hover:-translate-y-1 hover:shadow-[0_10px_30px_rgba(0,0,0,0.5)] hover:border-white/20 hover:bg-white/[0.03]"
                style={{
                  animation: `fade-in 0.5s ease-out forwards`,
                  animationDelay: `${idx * 100}ms`,
                  opacity: 0,
                }}
              >
                {/* 装饰层 */}
                <div className="absolute inset-0 bg-gradient-to-br from-amber-900/10 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-500 pointer-events-none" />
                <div className="absolute top-0 right-0 w-16 h-16 bg-[radial-gradient(circle_at_top_right,rgba(255,255,255,0.05),transparent_70%)] pointer-events-none" />

                <div className="p-5 flex flex-col h-full relative z-10">
                  <div className="flex items-start justify-between mb-4">
                    {/* 编号 + 标题 */}
                    <div className="flex flex-col gap-1.5">
                      <div className="flex items-center gap-2 text-stone-500 group-hover:text-amber-400 transition-colors">
                        <Skull size={12} strokeWidth={2} />
                        <span className="font-mono-retro text-[9px] tracking-widest font-bold">
                          NO.{String(idx + 1).padStart(3, '0')}
                        </span>
                      </div>
                      <span className="font-serif-sc text-lg text-stone-200 group-hover:text-white transition-colors tracking-wide drop-shadow-sm font-medium">
                        {ending.标题}
                      </span>
                    </div>

                    {/* 删除按钮 */}
                    {confirmDelete === ending.标题 ? (
                      <div className="flex items-center gap-1.5 shrink-0 bg-black/40 backdrop-blur-sm p-1 rounded-sm border border-amber-900/50">
                        <button
                          onClick={() => handleDelete(ending.标题)}
                          className="px-2 py-1 text-[9px] font-mono-retro tracking-widest text-amber-300 hover:bg-amber-900/50 hover:text-white transition-colors cursor-pointer rounded-sm"
                        >
                          CONFIRM
                        </button>
                        <button
                          onClick={() => {
                            playSfx();
                            setConfirmDelete(null);
                          }}
                          className="px-2 py-1 text-[9px] font-mono-retro tracking-widest text-stone-400 hover:bg-white/10 hover:text-white transition-colors cursor-pointer rounded-sm"
                        >
                          CANCEL
                        </button>
                      </div>
                    ) : (
                      <button
                        onClick={() => {
                          playSfx();
                          setConfirmDelete(ending.标题);
                        }}
                        className="w-8 h-8 flex items-center justify-center rounded-full bg-white/5 border border-white/5 text-stone-500 hover:text-amber-400 hover:border-amber-900/50 hover:bg-amber-950/30 opacity-0 group-hover:opacity-100 transition-all duration-300 cursor-pointer shadow-[0_0_10px_transparent] hover:shadow-[0_0_15px_rgba(245,158,11,0.2)]"
                        title="DELETE_ARCHIVE"
                      >
                        <Trash2 size={13} />
                      </button>
                    )}
                  </div>

                  {/* 描述 */}
                  {ending.描述 && (
                    <p className="font-serif-sc text-[13px] text-stone-400 leading-relaxed mt-auto border-t border-white/5 pt-3 group-hover:text-stone-300 transition-colors line-clamp-3">
                      {ending.描述}
                    </p>
                  )}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* 底部统计与装饰 */}
      <div className="relative z-10 mx-8 h-px bg-gradient-to-r from-transparent via-white/10 to-transparent" />
      <div className="relative z-10 px-8 py-4 flex items-center justify-between">
        <div className="flex gap-1 opacity-50">
          <div className="w-1 h-1 bg-white rounded-full" />
          <div className="w-1 h-1 bg-white rounded-full" />
          <div className="w-4 h-1 bg-white rounded-full" />
        </div>
        <div className="flex items-center gap-3">
          <span className="font-mono-retro text-[8px] text-stone-500 tracking-[0.2em] uppercase">
            ARCHIVES_RESTORED
          </span>
          <span className="font-mono-retro text-sm text-white tracking-widest font-bold">{endings.length}</span>
        </div>
      </div>
    </div>
  );
};
