import gsap from 'gsap';
import React, { useEffect, useLayoutEffect, useMemo, useRef, useState } from 'react';
import type { StatOverride } from '../types';

// svg components
const XIcon = ({ size, strokeWidth, className }: any) => (
  <svg
    xmlns="http://www.w3.org/2000/svg"
    width={size}
    height={size}
    viewBox="0 0 24 24"
    fill="none"
    stroke="currentColor"
    strokeWidth={strokeWidth}
    strokeLinecap="round"
    strokeLinejoin="round"
    className={className}
  >
    <line x1="18" y1="6" x2="6" y2="18" />
    <line x1="6" y1="6" x2="18" y2="18" />
  </svg>
);

const ArrowRightIcon = ({ size, className }: any) => (
  <svg
    xmlns="http://www.w3.org/2000/svg"
    width={size}
    height={size}
    viewBox="0 0 24 24"
    fill="none"
    stroke="currentColor"
    strokeWidth="2"
    strokeLinecap="round"
    strokeLinejoin="round"
    className={className}
  >
    <line x1="5" y1="12" x2="19" y2="12" />
    <polyline points="12 5 19 12 12 19" />
  </svg>
);

interface RelationshipData {
  付觉晓?: { 信任值: number };
  白河凛?: { 归属感: number };
  沈栖?: { 安全感: number };
}

interface RelationshipScreenProps {
  relationships: RelationshipData;
  displayOverrides?: StatOverride[];
  onClose: () => void;
  playSfx: () => void;
}

const CHARACTERS = [
  {
    id: '付觉晓',
    name: '付觉晓',
    enName: 'JUE XIAO',
    emotionName: '信任值',
    enEmotion: 'TRUST',
    img: 'https://raw.githubusercontent.com/2543400179-ux/res/refs/heads/master/char/1772467400701(3).png',
    getValue: (data: RelationshipData) => data.付觉晓?.信任值 ?? 0,
    tag: 'NO.01',
  },
  {
    id: '白河凛',
    name: '白河凛',
    enName: 'RIN',
    emotionName: '归属感',
    enEmotion: 'BELONGING',
    img: 'https://raw.githubusercontent.com/2543400179-ux/res/refs/heads/master/char/1772467405525(3).png',
    getValue: (data: RelationshipData) => data.白河凛?.归属感 ?? 0,
    tag: 'NO.02',
  },
  {
    id: '沈栖',
    name: '沈栖',
    enName: 'QI',
    emotionName: '安全感',
    enEmotion: 'SECURITY',
    img: 'https://raw.githubusercontent.com/2543400179-ux/res/refs/heads/master/char/1772467434987(3).png',
    getValue: (data: RelationshipData) => data.沈栖?.安全感 ?? 0,
    tag: 'NO.03',
  },
];

export const RelationshipScreen: React.FC<RelationshipScreenProps> = ({
  relationships,
  displayOverrides = [],
  onClose,
  playSfx,
}) => {
  const [activeIndex, setActiveIndex] = useState(0);
  const [prevIndex, setPrevIndex] = useState(-1);
  const activeChar = CHARACTERS[activeIndex];

  // 根据 displayOverrides 计算最终显示的属性值
  const displayedRelationships = useMemo(() => {
    const res = {
      付觉晓: { 信任值: relationships.付觉晓?.信任值 ?? 0 },
      白河凛: { 归属感: relationships.白河凛?.归属感 ?? 0 },
      沈栖: { 安全感: relationships.沈栖?.安全感 ?? 0 },
    };

    displayOverrides.forEach(s => {
      // s.path e.g. "付觉晓.信任值"
      const parts = s.path.split('.');
      if (parts.length === 2) {
        const char = parts[0] as keyof typeof res;
        const attr = parts[1];
        if (res[char] && attr in res[char]) {
          const charData = res[char] as any;
          if (s.mode === 'set') {
            charData[attr] = Number(s.value);
          } else if (s.mode === 'delta') {
            charData[attr] += Number(s.value);
          }
        }
      }
    });

    return res;
  }, [relationships, displayOverrides]);

  const overlayRef = useRef<HTMLDivElement>(null);
  const dataRef = useRef<HTMLDivElement>(null);
  const valueNumRef = useRef<HTMLSpanElement>(null);
  const imagesRef = useRef<(HTMLImageElement | null)[]>([]);

  // --- Custom Hook for Media Query ---
  const useMediaQuery = (query: string) => {
    const [matches, setMatches] = useState(window.matchMedia(query).matches);
    useEffect(() => {
      const media = window.matchMedia(query);
      const listener = () => setMatches(media.matches);
      media.addEventListener('change', listener);
      return () => media.removeEventListener('change', listener);
    }, [query]);
    return matches;
  };

  const isLandscape = useMediaQuery('(orientation: landscape)');

  // Initialize entry animation
  useEffect(() => {
    playSfx();
    if (overlayRef.current) {
      gsap.fromTo(overlayRef.current, { opacity: 0 }, { opacity: 1, duration: 0.8, ease: 'power2.out' });
    }
  }, [playSfx]);

  const handleClose = () => {
    playSfx();
    if (overlayRef.current) {
      gsap.to(overlayRef.current, {
        opacity: 0,
        duration: 0.5,
        ease: 'power2.in',
        onComplete: onClose,
      });
    } else {
      onClose();
    }
  };

  // Character and data animations
  useLayoutEffect(() => {
    const direction = prevIndex === -1 ? 1 : activeIndex > prevIndex ? 1 : -1;
    const xOffset = isLandscape ? 50 : 30; // Apply offset: right shift 80px in portrait, 50px in landscape

    // Animate Images
    imagesRef.current.forEach((img, idx) => {
      if (!img) return;

      if (idx === activeIndex) {
        // Animate the new active image into view
        gsap.fromTo(
          img,
          {
            x: 80 * direction + xOffset, // Start from an offset position
            scale: 0.95,
            rotation: 2 * direction,
            opacity: 0,
            filter: 'brightness(0) blur(20px)',
          },
          {
            x: xOffset, // End at the correct offset
            scale: 1,
            rotation: 0,
            opacity: 1,
            filter: 'brightness(1) blur(0px)',
            duration: 1.4,
            ease: 'expo.out',
            zIndex: 10,
          },
        );
      } else if (idx === prevIndex) {
        // Animate out the previous image
        gsap.to(img, {
          x: -80 * direction + xOffset, // Animate out to an offset position
          scale: 1.05,
          rotation: -2 * direction,
          opacity: 0,
          filter: 'brightness(0) blur(20px)',
          duration: 1,
          ease: 'power3.inOut',
          zIndex: 5,
        });
      } else {
        // Instantly set other images to the correct hidden state and position
        gsap.set(img, { opacity: 0, zIndex: 0, x: xOffset });
      }
    });

    // Animate Data Section
    if (dataRef.current) {
      gsap.fromTo(
        dataRef.current.children,
        { x: -40, y: 10, opacity: 0, skewX: 5 },
        { x: 0, y: 0, opacity: 1, skewX: 0, duration: 1, stagger: 0.08, ease: 'back.out(1.2)', clearProps: 'all' },
      );
    }

    // Animate Value Number
    if (valueNumRef.current) {
      const val = activeChar.getValue(displayedRelationships);
      const counter = { v: prevIndex === -1 ? 0 : Number(valueNumRef.current.textContent) || 0 };
      gsap.to(counter, {
        v: val,
        duration: 1.5,
        ease: 'power4.out',
        onUpdate: () => {
          if (valueNumRef.current) {
            valueNumRef.current.textContent = Math.round(counter.v).toString().padStart(2, '0');
          }
        },
      });
    }
  }, [activeIndex, prevIndex, displayedRelationships, activeChar, isLandscape]);

  const handleSelect = (idx: number) => {
    if (idx === activeIndex) return;
    playSfx();
    setPrevIndex(activeIndex);
    setActiveIndex(idx);
  };

  return (
    <div
      ref={overlayRef}
      className="fixed inset-0 z-50 flex flex-col landscape:flex-row bg-[#080808] text-[#e0e0e0] overflow-hidden font-sans select-none"
    >
      {/* Soft noise and base gradients for "airy/dreamlike" feel */}
      <div className="absolute inset-0 opacity-[0.04] mix-blend-overlay pointer-events-none bg-[url('https://grainy-gradients.vercel.app/noise.svg')]" />
      <div className="absolute inset-0 bg-gradient-to-br from-white/[0.02] via-transparent to-black/80 pointer-events-none z-0" />

      {/* --- Responsive Background Layout --- */}
      <div className="absolute top-0 left-0 w-full h-[60%] bg-transparent z-0 landscape:w-[55%] landscape:h-full lg:w-[65%]" />
      <div className="absolute bottom-0 right-0 w-full h-[40%] bg-gradient-to-t from-white/5 to-transparent z-0 landscape:hidden" />
      <div
        className="hidden landscape:block absolute top-0 right-0 w-[55%] h-full bg-gradient-to-l from-white/[0.03] to-transparent z-0 lg:w-[45%]"
        style={{ clipPath: 'polygon(15% 0, 100% 0, 100% 100%, 0 100%)' }}
      />

      {/* Soft glowing orbs for atmosphere */}
      <div className="absolute top-[-10%] left-[-10%] w-[50%] h-[50%] rounded-full bg-white/[0.03] blur-[100px] pointer-events-none" />
      <div className="absolute bottom-[-20%] right-[-10%] w-[60%] h-[60%] rounded-full bg-white/[0.02] blur-[120px] pointer-events-none" />

      {/* Decorative lines & elements - Monochrome */}
      <div className="absolute top-[12%] left-0 w-24 h-[1px] bg-gradient-to-r from-white/30 to-transparent z-0" />
      <div className="absolute bottom-[25%] left-0 w-32 h-[1px] bg-gradient-to-r from-white/10 to-transparent z-0 hidden lg:block" />
      <div className="absolute top-[35%] right-[40%] w-[1px] h-48 bg-gradient-to-b from-white/5 via-white/10 to-transparent z-0 hidden lg:block" />

      {/* Top Header */}
      <div className="absolute top-6 left-6 lg:top-10 lg:left-12 z-20 flex flex-col gap-1">
        <div className="flex items-center gap-2 lg:gap-4">
          <div className="w-8 lg:w-16 h-[1px] bg-white/50" />
          <span className="text-xs lg:text-sm font-sans tracking-[0.3em] font-light text-white/80">SYSTEM.BOND</span>
        </div>
        <span className="hidden lg:block text-[10px] font-sans text-white/30 tracking-[0.2em] uppercase ml-12">
          Neural Synchronization Interface
        </span>
      </div>

      <button
        onClick={handleClose}
        className="absolute top-6 right-6 lg:top-10 lg:right-12 z-50 flex items-center gap-4 text-white/50 hover:text-white transition-all cursor-pointer group"
      >
        <span className="hidden lg:block text-xs font-sans font-light tracking-[0.2em] opacity-0 group-hover:opacity-100 transition-opacity translate-x-2 group-hover:translate-x-0">
          CLOSE
        </span>
        <div className="border border-white/20 p-2 rounded-full backdrop-blur-md bg-white/5 group-hover:bg-white/20 group-hover:border-white/40 transition-all">
          <XIcon size={18} strokeWidth={1.5} className="lg:w-5 lg:h-5" />
        </div>
      </button>

      {/* Left/Main Visual Area */}
      <div className="relative w-full h-[60%] landscape:w-[55%] landscape:h-full lg:w-[65%] flex items-center z-10">
        {/* Background Effects */}
        <div className="absolute inset-0 pointer-events-none overflow-hidden">
          {/* Faded grid */}
          <div className="absolute inset-0 bg-[linear-gradient(rgba(255,255,255,0.02)_1px,transparent_1px),linear-gradient(90deg,rgba(255,255,255,0.02)_1px,transparent_1px)] bg-[size:60px_60px] [mask-image:radial-gradient(ellipse_70%_70%_at_50%_50%,#000_10%,transparent_100%)] opacity-40" />

          {/* Diagonal light rays */}
          <div className="absolute top-[-10%] left-[30%] w-[1px] h-[150%] bg-gradient-to-b from-transparent via-white/10 to-transparent rotate-[30deg] blur-[1px]" />
          <div className="absolute top-[-20%] left-[45%] w-[2px] h-[180%] bg-gradient-to-b from-transparent via-white/5 to-transparent rotate-[30deg] blur-[2px]" />

          <div className="absolute top-[8%] left-[4%] text-[18vh] lg:text-[25vh] font-sans font-black text-transparent [-webkit-text-stroke:1px_rgba(255,255,255,0.03)] leading-none tracking-[0.05em] uppercase select-none opacity-40 mix-blend-screen">
            {activeChar.enName}
          </div>
          <div className="absolute bottom-[20%] right-[0%] text-[10vh] lg:text-[15vh] font-sans font-black text-white/[0.02] leading-none tracking-[0.1em] uppercase select-none blur-[1px] italic text-right right-10">
            {activeChar.enEmotion}
          </div>

          {/* Technical decorations */}
          <div className="absolute top-[40%] left-[10%] flex-col gap-3 opacity-30 mix-blend-screen hidden lg:flex">
            {[...Array(5)].map((_, i) => (
              <div key={i} className="flex gap-3 items-center">
                <div className="w-[4px] h-[4px] rounded-full bg-white/60" />
                <div className="w-16 h-[1px] bg-gradient-to-r from-white/40 to-transparent" />
                <div className="text-[9px] font-mono text-white/50 tracking-[0.2em]">
                  ACT.{String(i + 1).padStart(2, '0')}
                </div>
              </div>
            ))}
          </div>

          {/* Circular abstract elements */}
          <div className="absolute bottom-[30%] left-[50%] w-64 h-64 lg:w-[350px] lg:h-[350px] rounded-full items-center justify-center opacity-20 mix-blend-screen hidden lg:flex">
            <div
              className="absolute w-[100%] h-[100%] border-[0.5px] border-white/20 rounded-full animate-[spin_30s_linear_infinite]"
              style={{ clipPath: 'polygon(0% 0%, 100% 0%, 100% 50%, 0% 50%)' }}
            />
            <div className="absolute w-[85%] h-[85%] border-[1px] border-white/10 rounded-full border-dashed animate-[spin_45s_linear_infinite_reverse]" />
            <div className="absolute w-[70%] h-[70%] border-[0.5px] border-white/15 rounded-full" />
            <div className="absolute w-full h-[1px] bg-gradient-to-r from-transparent via-white/20 to-transparent" />
            <div className="absolute h-full w-[1px] bg-gradient-to-b from-transparent via-white/20 to-transparent" />
          </div>
        </div>

        {/* Character Image List - Monochrome filter */}
        <div className="absolute bottom-0 left-1/2 -translate-x-1/2 w-full h-full landscape:h-[105%] lg:h-[130%] pointer-events-none flex items-end overflow-hidden justify-center">
          {CHARACTERS.map((char, idx) => (
            <img
              key={char.id}
              ref={el => {
                imagesRef.current[idx] = el;
              }}
              src={char.img}
              alt={char.name}
              className="absolute bottom-[-2%] h-full object-contain object-bottom origin-bottom mix-blend-screen"
              style={{
                filter: 'grayscale(100%) brightness(1.2) contrast(1.1) drop-shadow(0 0 20px rgba(255,255,255,0.15))',
                opacity: 0,
                maxWidth: '120%',
              }}
            />
          ))}
          {/* Delicate Image Overlays */}
          <div className="absolute inset-0 bg-gradient-to-t from-[#080808] via-[#080808]/50 to-transparent z-20 pointer-events-none h-[40%] bottom-0 self-end" />
          <div className="absolute bottom-0 w-full h-[25%] bg-gradient-to-t from-white/[0.03] to-transparent blur-2xl z-20 pointer-events-none" />
        </div>

        {/* Data Panel */}
        <div className="absolute bottom-8 left-8 lg:bottom-20 lg:left-20 z-30 flex flex-col" ref={dataRef}>
          <div className="flex items-center gap-3 lg:gap-5 mb-3 lg:mb-5">
            <div className="relative flex items-center justify-center w-8 h-8 lg:w-10 lg:h-10 group">
              <div className="absolute inset-0 border border-white/20 rounded-full animate-[spin_12s_linear_infinite]" />
              <div className="absolute inset-1.5 border-[0.5px] border-white/40 border-dashed rounded-full -rotate-45" />
              <div className="w-1.5 h-1.5 rounded-full bg-white/80 shadow-[0_0_8px_rgba(255,255,255,0.8)]" />
            </div>
            <div className="flex flex-col gap-0.5">
              <span className="text-white/80 font-mono font-light text-xs tracking-[0.4em]">{activeChar.tag}</span>
              <span className="text-white/30 font-mono text-[9px] tracking-[0.3em]">
                {activeChar.id.toUpperCase()}_LINK
              </span>
            </div>
          </div>

          <div className="relative inline-block w-fit">
            <h1 className="text-5xl lg:text-[6rem] font-sans font-light tracking-[0.1em] text-white/90 drop-shadow-[0_4px_20px_rgba(0,0,0,0.8)] landscape:drop-shadow-[0_4px_20px_rgba(255,255,255,0.1)] lg:drop-shadow-[0_4px_20px_rgba(255,255,255,0.1)] leading-[1.0] pr-2 lg:pr-4">
              {activeChar.name}
            </h1>
            <div className="absolute -left-4 lg:-left-6 top-[15%] w-[2px] h-[70%] bg-gradient-to-b from-white/80 to-transparent" />
          </div>

          <div className="flex items-center gap-4 lg:gap-8 mt-4 lg:mt-6 mb-4 lg:mb-8 ml-2">
            <div className="relative px-4 py-1.5 lg:px-6 lg:py-2.5 overflow-hidden backdrop-blur-md bg-white/5 border border-white/10 rounded-sm">
              <span className="relative z-10 text-white/90 font-sans font-light text-xs lg:text-sm tracking-[0.3em] uppercase block">
                {activeChar.emotionName}
              </span>
              <div className="absolute top-0 left-0 w-[2px] h-full bg-white/60" />
            </div>
            <div className="flex-col gap-1.5 hidden lg:flex">
              <span className="font-sans font-light text-[11px] tracking-[0.5em] text-white/40 uppercase">
                {activeChar.enEmotion}
              </span>
              <div className="w-40 h-[1px] bg-gradient-to-r from-white/20 to-transparent" />
            </div>
          </div>

          <div className="mt-2 flex items-baseline gap-3 lg:gap-5 ml-2 relative">
            <div className="absolute -inset-x-8 -inset-y-6 bg-gradient-to-r from-black/80 landscape:from-white/5 lg:from-white/5 to-transparent blur-xl lg:blur-2xl -z-10 rounded-full" />

            <span
              ref={valueNumRef}
              className="text-7xl lg:text-[9rem] leading-none py-2 font-sans font-light tracking-tighter text-transparent bg-clip-text bg-gradient-to-b from-white via-white/80 to-white/20 drop-shadow-[0_4px_20px_rgba(0,0,0,0.9)] landscape:drop-shadow-[0_0_30px_rgba(255,255,255,0.1)] lg:drop-shadow-[0_0_30px_rgba(255,255,255,0.1)]"
            >
              00
            </span>
            <div className="flex flex-col items-start gap-1 pb-2 lg:pb-4">
              <span className="text-xl lg:text-3xl font-sans font-light text-white/30 tracking-[0.1em]">/100</span>
              <span className="text-[9px] lg:text-[11px] font-mono text-white/60 tracking-[0.3em] px-1.5 py-0.5 border border-white/20 rounded-sm mt-1">
                MAX
              </span>
            </div>
          </div>
        </div>
      </div>

      {/* Right: Selection List */}
      <div className="relative w-full h-[40%] landscape:w-[45%] landscape:h-full lg:w-[35%] flex flex-col justify-center px-6 lg:px-0 lg:pl-12 lg:pr-24 z-10">
        {/* Right side decorative vertical line */}
        <div className="absolute right-12 top-[20%] bottom-[20%] w-[1px] bg-gradient-to-b from-transparent via-white/10 to-transparent hidden lg:block" />

        <div className="flex flex-col gap-3 lg:gap-6 w-full lg:max-w-[420px] mx-auto ml-0 lg:ml-auto">
          {CHARACTERS.map((char, idx) => {
            const isActive = idx === activeIndex;
            const val = char.getValue(displayedRelationships);

            return (
              <div
                key={char.id}
                onClick={() => handleSelect(idx)}
                className={`relative group cursor-pointer py-3 px-5 lg:py-7 lg:px-8 transition-all duration-700 ease-[cubic-bezier(0.2,0.8,0.2,1)] flex items-center overflow-hidden rounded-lg
                  ${
                    isActive
                      ? 'lg:-translate-x-4 scale-[1.02]'
                      : 'hover:-translate-x-2 hover:scale-[1.01] opacity-60 hover:opacity-100'
                  }`}
              >
                <div
                  className={`absolute inset-0 transition-all duration-700 rounded-lg border-[0.5px]
                    ${
                      isActive
                        ? 'bg-gradient-to-r from-white/[0.08] to-transparent backdrop-blur-xl border-white/20 shadow-[0_8px_32px_rgba(0,0,0,0.4)]'
                        : 'bg-white/[0.02] border-white/5 group-hover:bg-white/[0.04] group-hover:border-white/10'
                    }
                  `}
                />

                {/* Subtle active glow */}
                {isActive && (
                  <div className="absolute left-0 top-0 bottom-0 w-32 bg-gradient-to-r from-white/[0.05] to-transparent blur-md" />
                )}

                <div className="relative w-full flex justify-between items-center z-10 gap-4 lg:gap-6">
                  <div className="flex flex-col gap-2 flex-1">
                    <div className="flex items-center gap-3">
                      <div
                        className={`w-1.5 h-1.5 rounded-full transition-colors duration-500 ${isActive ? 'bg-white shadow-[0_0_5px_rgba(255,255,255,0.8)]' : 'bg-white/20'}`}
                      />
                      <span
                        className={`text-[9px] font-mono font-light tracking-[0.4em] transition-colors duration-500 ${isActive ? 'text-white/90' : 'text-white/40'}`}
                      >
                        {char.tag}
                      </span>
                    </div>
                    <span
                      className={`text-xl lg:text-[1.8rem] font-sans font-light tracking-[0.1em] transition-colors duration-500 leading-none ${isActive ? 'text-white drop-shadow-[0_0_8px_rgba(255,255,255,0.2)]' : 'text-white/60'}`}
                    >
                      {char.name}
                    </span>
                    <div className="flex items-center gap-3 mt-1">
                      <span
                        className={`text-[9px] font-sans font-light tracking-[0.3em] uppercase transition-colors duration-500 ${isActive ? 'text-white/60' : 'text-white/20'}`}
                      >
                        {char.enName}
                      </span>
                      <div
                        className={`h-[1px] flex-1 transition-all duration-700 ${isActive ? 'bg-gradient-to-r from-white/20 to-transparent' : 'bg-transparent'}`}
                      />
                    </div>
                  </div>

                  <div className="flex items-center gap-4 lg:gap-8">
                    <div className="flex flex-col items-end">
                      <span
                        className={`font-sans font-light text-2xl lg:text-4xl transition-colors duration-500 ${isActive ? 'text-white' : 'text-white/40'}`}
                      >
                        {Math.round(val)}
                        <span className="text-xs lg:text-sm ml-1 opacity-50 font-light">%</span>
                      </span>
                      {isActive && (
                        <div className="text-[9px] text-white/60 font-mono tracking-[0.3em] mt-1">SYNCED</div>
                      )}
                    </div>

                    <div className="relative w-8 h-8 lg:w-10 lg:h-10 flex items-center justify-center overflow-hidden rounded-full">
                      <div
                        className={`absolute inset-0 border transition-all duration-500 rounded-full ${isActive ? 'border-white/40 bg-white/5 scale-100' : 'border-white/10 scale-75 opacity-0 group-hover:scale-90 group-hover:opacity-100'}`}
                      />
                      <ArrowRightIcon
                        size={18}
                        className={`relative z-10 transition-all duration-500 ${isActive ? 'text-white translate-x-0' : 'text-white/30 -translate-x-2 group-hover:text-white/60 group-hover:translate-x-0'}`}
                      />
                    </div>
                  </div>
                </div>

                {/* Progress bar */}
                <div className="absolute bottom-0 left-0 w-full h-[2px] bg-white/[0.02]">
                  <div
                    className={`h-full transition-all duration-1000 ease-[cubic-bezier(0.2,0.8,0.2,1)] flex ${isActive ? 'opacity-100' : 'opacity-30'}`}
                    style={{ width: isActive ? `${val}%` : '0%' }}
                  >
                    <div className="h-full bg-white/80 flex-1 shadow-[0_0_8px_rgba(255,255,255,0.5)]" />
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
};
