interface StatusScreenProps {
  character: CharacterProfile;
  /** 由 [desc:] 指令驱动的角色描述，优先于 character.description */
  description?: string;
  /** 由 [bg:] 指令驱动的世界状态（场景/威胁度/时间） */
  bgWorldState: BgWorldState;
  /** 段落级状态覆写（由 [stat:] 指令驱动，临时覆盖显示） */
  displayOverrides?: StatOverride[];
  onClose: () => void;
  playSfx: () => void;
  /** 头像 URL 变更回调（持久化到酒馆变量） */
  onAvatarChange?: (url: string) => void;
}

/** 将 StatOverride[] 转为 path→StatOverride 的 Map，保留 mode 信息 */
function buildOverrideMap(overrides?: StatOverride[]): Map<string, StatOverride> {
  const map = new Map<string, StatOverride>();
  if (!overrides) return map;
  for (const o of overrides) {
    map.set(o.path, o);
  }
  return map;
}

/** 获取覆写后的值：delta 模式叠加到 MVU 底值，set 模式直接替换 */
function getOverridden<T>(overrideMap: Map<string, StatOverride>, path: string, mvuValue: T): T {
  const o = overrideMap.get(path);
  if (!o) return mvuValue;
  if (o.mode === 'delta' && typeof o.value === 'number' && typeof mvuValue === 'number') {
    return (mvuValue + o.value) as unknown as T;
  }
  return o.value as unknown as T;
}

const THREAT_COLORS: Record<ThreatLevel, string> = {
  安全: 'text-stone-300 border-stone-600 bg-stone-800/30',
  低: 'text-stone-400 border-stone-700 bg-stone-900/30',
  中: 'text-stone-200 border-stone-500 bg-stone-700/30',
  高: 'text-white border-stone-400 bg-stone-600/40',
  极危: 'text-white border-white bg-stone-400/50 animate-pulse',
};

/** 从 displayOverrides 中提取 技能.* 路径的覆写，叠加到 MVU 底值上 */
function mergeSkillsWithOverrides(
  mvuSkills: Record<string, any>,
  overrides?: StatOverride[],
): Record<string, { 等级: number; 描述?: string }> {
  // 以 MVU 真实技能为底
  const skills: Record<string, { 等级: number; 描述?: string }> = {};
  if (mvuSkills && typeof mvuSkills === 'object') {
    for (const [name, val] of Object.entries(mvuSkills)) {
      const lvl = typeof val === 'object' && val !== null ? Number(_.get(val, '等级', 1)) || 1 : 1;
      const desc = typeof val === 'object' && val !== null ? _.get(val, '描述', '') : '';
      skills[name] = { 等级: lvl, ...(desc ? { 描述: desc } : {}) };
    }
  }
  // 叠加 [stat:] 覆写
  if (overrides) {
    for (const o of overrides) {
      // 匹配技能等级覆写: 技能.潜行 或 技能.潜行.等级
      const lvlMatch = o.path.match(/^技能\.([^.]+)(?:\.等级)?$/);
      if (lvlMatch) {
        const name = lvlMatch[1];
        const numVal = typeof o.value === 'number' ? o.value : parseInt(String(o.value)) || 1;
        if (o.mode === 'delta') {
          // 增量：在 MVU 底值上累加
          const base = skills[name]?.等级 ?? 0;
          skills[name] = { ...skills[name], 等级: base + numVal };
        } else {
          // 赋值：直接设置
          skills[name] = { ...skills[name], 等级: numVal };
        }
        continue;
      }

      // 匹配技能描述覆写: 技能.潜行.描述
      const descMatch = o.path.match(/^技能\.([^.]+)\.描述$/);
      if (descMatch) {
        const name = descMatch[1];
        const descVal = String(o.value);
        // 确保技能存在
        if (!skills[name]) {
          skills[name] = { 等级: 1 };
        }
        skills[name] = { ...skills[name], 描述: descVal };
      }
    }
  }
  return skills;
}

/** 从 displayOverrides 中提取 背包.* 路径的覆写，叠加到 MVU 底值上 */
function mergeInventoryWithOverrides(
  mvuInventory: Record<string, any>,
  overrides?: StatOverride[],
): Record<string, { 数量: number }> {
  // 以 MVU 真实背包为底
  const inv: Record<string, { 数量: number }> = {};
  if (mvuInventory && typeof mvuInventory === 'object') {
    for (const [name, val] of Object.entries(mvuInventory)) {
      const qty = typeof val === 'object' && val !== null ? Number(_.get(val, '数量', 1)) || 1 : 1;
      if (qty > 0) {
        inv[name] = { 数量: qty };
      }
    }
  }
  // 叠加 [stat:] 覆写
  if (overrides) {
    for (const o of overrides) {
      const m = o.path.match(/^背包\.([^.]+)(?:\.数量)?$/);
      if (m) {
        const name = m[1];
        const numVal = typeof o.value === 'number' ? o.value : parseInt(String(o.value)) || 1;
        let qty: number;
        if (o.mode === 'delta') {
          // 增量：在 MVU 底值上累加
          const base = inv[name]?.数量 ?? 0;
          qty = base + numVal;
        } else {
          // 赋值：直接设置
          qty = numVal;
        }
        if (qty > 0) {
          inv[name] = { 数量: qty };
        } else {
          delete inv[name];
        }
      }
    }
  }
  return inv;
}

export const StatusScreen: React.FC<StatusScreenProps> = ({
  character,
  description,
  bgWorldState,
  displayOverrides,
  onClose,
  playSfx,
  onAvatarChange,
}) => {
  const overrideMap = useMemo(() => buildOverrideMap(displayOverrides), [displayOverrides]);

  // ====== 头像 URL 编辑弹窗状态 ======
  const [showAvatarModal, setShowAvatarModal] = useState(false);
  const [avatarInput, setAvatarInput] = useState(character.avatarUrl || '');
  const [avatarPreviewError, setAvatarPreviewError] = useState(false);

  // 应用覆写到 vitals/attributes — 以 MVU 真实值为底，[stat:] 覆写叠加在上面
  const vitals = {
    temperature: getOverridden(overrideMap, '体温', character.vitals.temperature),
    antibody: getOverridden(overrideMap, '抗体', character.vitals.antibody),
    trauma: getOverridden(overrideMap, '创伤', character.vitals.trauma),
    identity: getOverridden(overrideMap, '身份', character.vitals.identity),
    load: {
      current: getOverridden(overrideMap, '负重.当前', character.vitals.load.current),
      max: getOverridden(overrideMap, '负重.上限', character.vitals.load.max),
    },
  };
  const attributes = {
    strength: getOverridden(overrideMap, '力量', character.attributes.strength),
    agility: getOverridden(overrideMap, '敏捷', character.attributes.agility),
    endurance: getOverridden(overrideMap, '体力', character.attributes.endurance),
  };

  const loadPercent = Math.min(100, (vitals.load.current / vitals.load.max) * 100);

  // 技能和背包：以 MVU 真实值为底，[stat:] 覆写叠加变化
  const skillEntries = Object.entries(
    useMemo(() => mergeSkillsWithOverrides(character.skills, displayOverrides), [character.skills, displayOverrides]),
  );
  const inventoryEntries = Object.entries(
    useMemo(
      () => mergeInventoryWithOverrides(character.inventory, displayOverrides),
      [character.inventory, displayOverrides],
    ),
  );

  // ====== 高亮动画：追踪哪些 path 发生了变化 ======
  const prevOverridesRef = useRef<string>('');
  const [highlightedPaths, setHighlightedPaths] = useState<Map<string, 'up' | 'down' | 'change'>>(new Map());

  useEffect(() => {
    const key = JSON.stringify(displayOverrides || []);
    if (key === prevOverridesRef.current) return;
    prevOverridesRef.current = key;

    if (!displayOverrides || displayOverrides.length === 0) {
      setHighlightedPaths(new Map());
      return;
    }

    // 对比覆写值与角色原始值，确定变化方向
    const newHighlights = new Map<string, 'up' | 'down' | 'change'>();
    const origMap: Record<string, number | string> = {
      力量: character.attributes.strength,
      敏捷: character.attributes.agility,
      体力: character.attributes.endurance,
      体温: character.vitals.temperature,
      '负重.当前': character.vitals.load.current,
      '负重.上限': character.vitals.load.max,
    };

    for (const o of displayOverrides) {
      if (o.mode === 'delta' && typeof o.value === 'number') {
        // delta 模式：增量值本身就表示方向
        if (o.value > 0) newHighlights.set(o.path, 'up');
        else if (o.value < 0) newHighlights.set(o.path, 'down');
      } else {
        // set 模式：对比覆写值与 MVU 底值
        const orig = origMap[o.path];
        if (orig !== undefined && typeof o.value === 'number' && typeof orig === 'number') {
          if (o.value > orig) newHighlights.set(o.path, 'up');
          else if (o.value < orig) newHighlights.set(o.path, 'down');
        } else {
          newHighlights.set(o.path, 'change');
        }
      }
    }

    setHighlightedPaths(newHighlights);

    // 1.5s 后清除高亮
    const timer = setTimeout(() => setHighlightedPaths(new Map()), 1500);
    return () => clearTimeout(timer);
  }, [displayOverrides, character]);

  /** 获取某个 path 的高亮 CSS class */
  const getHighlightClass = (path: string): string => {
    const dir = highlightedPaths.get(path);
    if (!dir) return '';
    if (dir === 'up') return 'animate-pulse text-white drop-shadow-[0_0_8px_rgba(255,255,255,0.8)]';
    if (dir === 'down') return 'animate-pulse text-stone-500';
    return 'animate-pulse text-stone-300 drop-shadow-[0_0_4px_rgba(255,255,255,0.4)]';
  };

  useEffect(() => {
    playSfx();
  }, []);

  const handleClose = () => {
    playSfx();
    onClose();
  };

  return (
    <div className="game-modal absolute inset-0 z-50 flex items-center justify-center p-4 md:p-12 bg-black/70 backdrop-blur-xl animate-in fade-in duration-500">
      {/* Decorative large background text */}
      <div className="absolute top-1/4 left-[-2%] text-[25vw] font-black italic text-white/[0.015] pointer-events-none whitespace-nowrap -rotate-6 select-none font-serif tracking-tighter">
        STATUS
      </div>

      {/* External Close Button - purely floating outside */}
      <div className="absolute top-6 right-6 md:top-10 md:right-10 z-[60] flex items-center gap-4">
        <span className="text-[10px] font-mono-retro tracking-[0.3em] text-white/30 uppercase hidden md:block">
          Close panel
        </span>
        <button
          onClick={handleClose}
          className="p-3 md:p-4 rounded-full bg-white/[0.02] border border-white/10 text-stone-400 hover:text-white hover:bg-white/10 hover:border-white/30 transition-all duration-500 group shadow-lg backdrop-blur-md"
        >
          <X size={20} className="group-hover:rotate-90 transition-transform duration-500" />
        </button>
      </div>

      <div className="relative w-full max-w-[68rem] h-full max-h-[88vh] bg-stone-950/30 backdrop-blur-[32px] flex flex-col rounded-[2rem] border border-white/5 shadow-[0_40px_100px_rgba(0,0,0,0.9),inset_0_1px_1px_rgba(255,255,255,0.1)] overflow-hidden">
        {/* Dynamic Abstract Background inside panel - High Transparency */}
        <div className="absolute inset-0 z-0 pointer-events-none overflow-hidden rounded-[2rem]">
          <div className="absolute -top-[20%] -right-[10%] w-[60%] h-[70%] rounded-full bg-white/[0.08] blur-[100px] mix-blend-screen" />
          <div className="absolute bottom-[-10%] left-[-10%] w-[50%] h-[50%] rounded-full bg-white/[0.04] blur-[80px] mix-blend-screen" />
          {/* Extremely subtle horizontal scanlines to add texture */}
          <div className="absolute inset-0 bg-[linear-gradient(transparent_50%,rgba(0,0,0,0.1)_50%)] bg-[size:100%_4px] mix-blend-overlay opacity-30" />
        </div>
        <div className="absolute inset-0 bg-gradient-to-b from-transparent via-black/20 to-black/60 pointer-events-none -z-0 rounded-[2rem]" />

        {/* Edge highlights for extra glass feel */}
        <div className="absolute top-0 left-1/4 w-[40%] h-[1px] bg-gradient-to-r from-transparent via-white/20 to-transparent" />

        {/* --- HEADER: Identity (Glassmorphism & Large Typography) --- */}
        <div className="relative z-10 px-8 py-8 md:px-12 md:py-10 flex flex-col md:flex-row items-center md:items-start gap-8 md:gap-10 shrink-0 border-b border-white/5 bg-gradient-to-b from-white/[0.02] to-transparent rounded-t-[2rem]">
          {/* Avatar Section */}
          <div className="flex flex-col items-center gap-4">
            <div className="relative group">
              <div
                className="relative w-28 h-28 md:w-40 md:h-40 rounded-[1.5rem] shrink-0 overflow-hidden cursor-pointer border border-white/10 transition-all duration-700 shadow-[0_15px_40px_rgba(0,0,0,0.5)] group-hover:shadow-[0_20px_50px_rgba(255,255,255,0.05)] group-hover:border-white/30"
                onClick={() => {
                  playSfx();
                  setAvatarInput(character.avatarUrl || '');
                  setAvatarPreviewError(false);
                  setShowAvatarModal(true);
                }}
                title="点击设置头像"
              >
                {character.avatarUrl ? (
                  <img
                    src={character.avatarUrl}
                    className="absolute inset-0 w-full h-full object-cover transition-transform duration-1000 group-hover:scale-[1.05] filter grayscale-[0.2] group-hover:grayscale-0"
                    alt="Portrait"
                  />
                ) : (
                  <div className="absolute inset-0 flex items-center justify-center bg-white/[0.02]">
                    <User size={40} className="text-stone-600 font-light" />
                  </div>
                )}
                {/* Elegant subtle inner shadow instead of scanline */}
                <div className="absolute inset-0 shadow-[inset_0_0_20px_rgba(0,0,0,0.5)] pointer-events-none" />
                {/* Hover Overlay */}
                <div className="absolute inset-0 bg-black/40 backdrop-blur-sm flex items-center justify-center opacity-0 group-hover:opacity-100 transition-all duration-500">
                  <Camera size={24} className="text-white/80 drop-shadow-md" />
                </div>
              </div>

              {/* Corner decorative bracket */}
              <div className="absolute -top-2 -left-2 w-4 h-4 border-t border-l border-white/30 pointer-events-none" />
              <div className="absolute -bottom-2 -right-2 w-4 h-4 border-b border-r border-white/30 pointer-events-none" />
            </div>

            {/* Identity Badge */}
            <div className="inline-flex items-center gap-2 mt-1 px-4 py-1.5 bg-black/20 border border-white/5 rounded-full backdrop-blur-md">
              <span className="w-1 h-1 bg-white rounded-full shadow-[0_0_8px_rgba(255,255,255,0.8)]" />
              <span className="text-[11px] font-serif-sc text-stone-300 tracking-[0.2em]">{vitals.identity}</span>
            </div>
          </div>

          {/* Details Section */}
          <div className="flex-1 flex flex-col items-center md:items-start text-center md:text-left pt-2">
            <div className="flex flex-col items-center md:items-start gap-1 mb-2">
              <div className="text-[10px] font-mono-retro text-stone-500 tracking-[0.4em] uppercase flex items-center gap-4">
                <span>ID. {character.codeName}</span>
                <div className="h-px w-12 bg-white/20 hidden md:block" />
              </div>
            </div>

            <h1 className="text-4xl md:text-5xl lg:text-6xl font-serif-sc font-light text-white tracking-[0.2em] drop-shadow-xl mb-4">
              {character.name}
            </h1>

            {/* Description Preview (if any) */}
            <div className="text-sm font-serif-sc text-stone-300/60 leading-loose max-w-2xl line-clamp-2 hidden md:block border-l px-5 border-white/10 bg-gradient-to-r from-white/[0.02] to-transparent py-1">
              {description || character.description}
            </div>
          </div>

          {/* Important Stat Display (Antibody) - Ultra Minimal */}
          <div className="flex flex-col items-center justify-center md:items-end gap-1 shrink-0 md:pl-10">
            <div className="flex items-center gap-2 opacity-50 mb-1">
              <span className="text-[9px] font-mono-retro text-stone-100 tracking-[0.3em] uppercase">SYNC_RATE</span>
              <ShieldAlert size={10} className="text-stone-100" />
            </div>
            <div className="flex items-baseline gap-1 relative">
              <div className="text-6xl md:text-8xl font-extralight font-mono-retro text-white tracking-tighter drop-shadow-[0_0_25px_rgba(255,255,255,0.2)]">
                {vitals.antibody}
              </div>
              <span className="text-xl md:text-3xl text-stone-500 font-extralight opacity-50">%</span>
            </div>
          </div>
        </div>

        {/* --- WORLD STATE BAR (bg 指令驱动) --- */}
        <div className="relative z-10 px-8 md:px-12 py-3 bg-black/20 border-b border-white/5 flex flex-wrap md:flex-nowrap items-center justify-between md:justify-start gap-6 md:gap-10 text-[10px] font-mono-retro tracking-widest text-stone-400">
          {bgWorldState.时间 && (
            <div className="flex items-center gap-2 text-stone-300">
              <Clock size={14} className="text-stone-500 shrink-0" />
              <span className="tracking-[0.1em]">{bgWorldState.时间}</span>
            </div>
          )}
          {bgWorldState.时间 && <div className="hidden md:block w-px h-4 bg-stone-700/50" />}

          <div className="flex items-center gap-2 text-stone-300">
            <MapPin size={14} className="text-stone-500 shrink-0" />
            <span className="tracking-[0.1em]">{bgWorldState.场景 || 'UNKNOWN_SECTOR'}</span>
          </div>

          <div className="hidden md:block w-px h-4 bg-stone-700/50" />

          <div
            className={`flex items-center gap-2 px-3 py-1 rounded-sm border backdrop-blur-sm ${THREAT_COLORS[bgWorldState.威胁等级] || THREAT_COLORS['低']}`}
          >
            <span className="tracking-[0.2em] uppercase text-[10px]">THREAT: {bgWorldState.威胁等级}</span>
          </div>
        </div>

        {/* --- CONTENT GRID --- */}
        <div className="relative z-10 px-8 py-8 md:px-12 md:py-10 grid grid-cols-1 md:grid-cols-[1fr_1.1fr] gap-10 md:gap-16 overflow-y-auto min-h-0 custom-scrollbar pb-12">
          {/* LEFT COLUMN: CORE ATTRIBUTES + SKILLS */}
          <div className="flex flex-col gap-12 pr-2">
            {/* Core Attributes */}
            <div>
              <div className="flex items-center gap-4 mb-6">
                <h3 className="text-[11px] font-mono-retro text-white/50 tracking-[0.3em] uppercase">ATTRIBUTES</h3>
                <div className="flex-1 h-[1px] bg-white/5" />
              </div>

              <div className="flex flex-col gap-3">
                <AttributeRowInfinite
                  icon={<Dumbbell size={16} />}
                  label="STR"
                  cnLabel="力量"
                  value={attributes.strength}
                  highlightClass={getHighlightClass('力量')}
                />
                <AttributeRowInfinite
                  icon={<Wind size={16} />}
                  label="AGI"
                  cnLabel="敏捷"
                  value={attributes.agility}
                  highlightClass={getHighlightClass('敏捷')}
                />
                <AttributeRowInfinite
                  icon={<HeartPulse size={16} />}
                  label="END"
                  cnLabel="体力"
                  value={attributes.endurance}
                  highlightClass={getHighlightClass('体力')}
                />
              </div>
            </div>

            {/* Skills */}
            <div className="flex-1 min-h-0 flex flex-col">
              <div className="flex items-center gap-4 mb-6">
                <h3 className="text-[11px] font-mono-retro text-white/50 tracking-[0.3em] uppercase">SKILLS</h3>
                <div className="flex-1 h-[1px] bg-white/5" />
              </div>

              <div className="overflow-y-auto custom-scrollbar pr-3 flex-1 space-y-1">
                {skillEntries.length > 0 ? (
                  skillEntries.map(([name, skill]) => (
                    <div
                      key={name}
                      className="group relative flex flex-col py-3 px-4 hover:bg-white/[0.02] transition-colors duration-300"
                    >
                      <div className="absolute left-0 top-1/2 -translate-y-1/2 w-[2px] h-0 bg-white/40 group-hover:h-2/3 transition-all duration-300" />
                      <div className="flex items-center justify-between mb-1.5">
                        <span className="text-sm font-serif-sc text-stone-300 group-hover:text-white transition-colors tracking-widest">
                          {name}
                        </span>
                        <div className="flex items-center gap-3">
                          <div className="flex gap-[3px]">
                            {[...Array(Math.min(5, skill.等级))].map((_, i) => (
                              <div
                                key={i}
                                className="w-1 h-3 bg-white/40 group-hover:bg-white/80 transition-colors skew-x-[-15deg]"
                              />
                            ))}
                            {skill.等级 > 5 && (
                              <span className="text-[10px] font-mono-retro text-white/80 ml-1">+{skill.等级 - 5}</span>
                            )}
                          </div>
                          <span className="text-xs font-mono-retro text-stone-500 w-4 text-right">{skill.等级}</span>
                        </div>
                      </div>
                      {skill.描述 && (
                        <div className="text-[11px] font-serif-sc text-stone-500/80 group-hover:text-stone-400 leading-relaxed transition-colors">
                          {skill.描述}
                        </div>
                      )}
                    </div>
                  ))
                ) : (
                  <div className="text-[10px] font-mono-retro text-stone-600/50 py-8 text-center tracking-widest border border-dashed border-white/5">
                    NULL
                  </div>
                )}
              </div>
            </div>
          </div>

          {/* RIGHT COLUMN: VITALS & INVENTORY (Cards approach) */}
          <div className="flex flex-col gap-8">
            {/* Vitals Cards Grid - Monochrome minimal */}
            <div className="grid grid-cols-2 gap-5">
              {/* Load Card */}
              <div className="col-span-2 bg-white/[0.01] border border-white/[0.05] hover:border-white/20 transition-all p-5 rounded-xl backdrop-blur-sm">
                <div className="flex justify-between items-end mb-4">
                  <div className="flex items-center gap-3">
                    <Box size={14} className="text-stone-400" />
                    <span className="text-[11px] font-mono-retro text-stone-400 tracking-[0.2em] uppercase">
                      CARGO_LOAD
                    </span>
                  </div>
                  <span className="font-mono-retro text-lg text-white font-light tracking-widest">
                    {vitals.load.current} <span className="text-stone-500 text-xs">/ {vitals.load.max} KG</span>
                  </span>
                </div>
                {/* Thin elegant monochrome progress bar */}
                <div className="h-[2px] w-full bg-white/10 overflow-hidden relative">
                  <div
                    className={`absolute top-0 left-0 h-full transition-all duration-[1s] ease-out
                      ${loadPercent > 90 ? 'bg-white shadow-[0_0_10px_white] animate-pulse' : loadPercent > 70 ? 'bg-stone-300' : 'bg-stone-500'}`}
                    style={{ width: `${loadPercent}%` }}
                  />
                  {/* Overload indicator pattern */}
                  {loadPercent > 90 && (
                    <div className="absolute inset-0 bg-[repeating-linear-gradient(45deg,transparent,transparent_2px,black_2px,black_4px)] opacity-50" />
                  )}
                </div>
              </div>

              {/* Temp Card */}
              <div className="bg-white/[0.01] border border-white/[0.05] hover:border-white/20 transition-all p-5 rounded-xl relative overflow-hidden flex flex-col justify-between aspect-[2/1] backdrop-blur-sm">
                <div className="flex justify-between items-start z-10">
                  <span className="text-[10px] font-mono-retro text-stone-500 tracking-[0.2em]">CORE_TEMP</span>
                  <Thermometer size={14} className="text-stone-500" />
                </div>
                <div className="relative z-10 flex items-baseline gap-1 mt-2">
                  <span
                    className={`text-4xl font-mono-retro font-extralight transition-colors duration-500
                    ${getHighlightClass('体温') || (vitals.temperature > 37.5 ? 'text-white drop-shadow-[0_0_12px_rgba(255,255,255,0.6)] animate-pulse' : 'text-stone-300')}
                  `}
                  >
                    {vitals.temperature}
                  </span>
                  <span className="text-sm font-mono-retro text-stone-600">°C</span>
                </div>
              </div>

              {/* Trauma Card */}
              <div className="bg-white/[0.01] border border-white/[0.05] hover:border-white/20 transition-all p-5 rounded-xl relative overflow-hidden flex flex-col justify-between aspect-[2/1] backdrop-blur-sm">
                <div className="flex justify-between items-start z-10 mb-2">
                  <span className="text-[10px] font-mono-retro text-stone-500 tracking-[0.2em]">TRAUMA</span>
                  <Skull size={14} className="text-stone-500" />
                </div>
                <div
                  className={`text-sm font-serif-sc leading-relaxed transition-colors duration-500 line-clamp-2
                  ${getHighlightClass('创伤') || (vitals.trauma !== '无' ? 'text-white' : 'text-stone-400')}
                `}
                >
                  {vitals.trauma}
                </div>
              </div>
            </div>

            {/* Inventory List */}
            <div className="flex-1 flex flex-col bg-white/[0.01] border border-white/[0.05] p-5 rounded-xl min-h-[200px] backdrop-blur-sm">
              <div className="flex items-center gap-4 mb-6">
                <Backpack size={14} className="text-stone-500" />
                <h3 className="text-[11px] font-mono-retro text-white/50 tracking-[0.3em] uppercase">INVENTORY</h3>
                <div className="flex-1 h-[1px] bg-white/5" />
              </div>

              <div className="flex-1 overflow-y-auto custom-scrollbar pr-3 space-y-1">
                {inventoryEntries.length > 0 ? (
                  inventoryEntries.map(([name, item]) => (
                    <div
                      key={name}
                      className="group flex items-center justify-between px-4 py-2.5 hover:bg-white/[0.03] transition-colors duration-300 rounded-sm"
                    >
                      <span className="text-sm font-serif-sc text-stone-300 group-hover:text-white tracking-widest">
                        {name}
                      </span>
                      <div className="flex items-center gap-3">
                        <div className="w-12 h-px bg-white/10 group-hover:bg-white/30 transition-colors" />
                        <span className="text-[9px] font-mono-retro text-stone-500 uppercase">x</span>
                        <span className="text-sm font-mono-retro font-light text-stone-300 group-hover:text-white w-6 text-right">
                          {item.数量}
                        </span>
                      </div>
                    </div>
                  ))
                ) : (
                  <div className="text-[10px] font-mono-retro text-stone-600/50 py-8 text-center tracking-widest border border-dashed border-white/5">
                    STORAGE_EMPTY
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* ====== 头像 URL 编辑弹窗 ====== */}
      {showAvatarModal && (
        <div
          className="absolute inset-0 z-[60] flex items-center justify-center bg-black/80 backdrop-blur-sm animate-in fade-in duration-200"
          onClick={() => setShowAvatarModal(false)}
        >
          <div
            className="w-full max-w-sm mx-4 bg-stone-950 border border-stone-700/40 shadow-2xl relative overflow-hidden"
            onClick={e => e.stopPropagation()}
          >
            {/* 顶部装饰线 */}
            <div className="absolute top-0 left-0 right-0 h-[1px] bg-gradient-to-r from-transparent via-white/40 to-transparent" />

            {/* Header */}
            <div className="flex justify-between items-center px-5 py-4 border-b border-stone-800/50">
              <div className="flex items-center gap-3">
                <Camera size={14} className="text-stone-400" />
                <span className="font-mono-retro text-xs text-stone-300 tracking-[0.2em] font-light">PORTRAIT_CFG</span>
              </div>
              <button
                onClick={() => setShowAvatarModal(false)}
                className="w-7 h-7 flex items-center justify-center text-stone-600 hover:text-white transition-colors cursor-pointer"
              >
                <X size={14} />
              </button>
            </div>

            {/* 预览区域 */}
            <div className="px-5 pt-4 flex justify-center">
              <div className="relative w-20 h-24 bg-stone-900 border border-stone-800 overflow-hidden">
                {avatarInput && !avatarPreviewError ? (
                  <img
                    src={avatarInput}
                    className="absolute inset-0 w-full h-full object-cover"
                    alt="Preview"
                    onError={() => setAvatarPreviewError(true)}
                    onLoad={() => setAvatarPreviewError(false)}
                  />
                ) : avatarPreviewError ? (
                  <div className="absolute inset-0 flex items-center justify-center bg-stone-900">
                    <span className="text-[8px] font-mono-retro text-stone-500 tracking-widest">ERR_LOAD</span>
                  </div>
                ) : (
                  <div className="absolute inset-0 flex items-center justify-center bg-stone-950">
                    <User size={36} className="text-stone-800 font-light" />
                  </div>
                )}
              </div>
            </div>

            {/* URL 输入 */}
            <div className="px-5 py-5 space-y-4">
              <div className="flex items-center gap-2">
                <Link size={12} className="text-stone-500 shrink-0" />
                <span className="text-[10px] font-mono-retro text-stone-400 tracking-[0.2em] uppercase">SRC_URL</span>
              </div>
              <input
                type="text"
                value={avatarInput}
                onChange={e => {
                  setAvatarInput(e.target.value);
                  setAvatarPreviewError(false);
                }}
                placeholder="https://.../avatar.jpg"
                className="w-full bg-stone-900/80 border-b border-stone-700 text-xs font-mono-retro text-stone-200 px-3 py-2.5 placeholder:text-stone-700 focus:outline-none focus:border-stone-400 transition-colors"
              />
              <p className="text-[9px] font-serif-sc text-stone-600 leading-relaxed tracking-wider">
                Support image url for portrait.
              </p>
            </div>

            {/* 操作按钮 */}
            <div className="px-5 pb-5 flex gap-3">
              {character.avatarUrl && (
                <button
                  onClick={() => {
                    playSfx();
                    onAvatarChange?.('');
                    setAvatarInput('');
                    setShowAvatarModal(false);
                  }}
                  className="flex items-center gap-2 px-4 py-2 border border-stone-800 text-stone-500 hover:text-white hover:border-white/30 transition-all cursor-pointer"
                >
                  <Trash2 size={12} />
                  <span className="text-[10px] font-mono-retro tracking-widest">DEL</span>
                </button>
              )}
              <div className="flex-1" />
              <button
                onClick={() => {
                  playSfx();
                  onAvatarChange?.(avatarInput.trim());
                  setShowAvatarModal(false);
                }}
                disabled={avatarPreviewError}
                className="flex items-center gap-2 px-6 py-2 bg-white text-black hover:bg-stone-300 transition-all cursor-pointer disabled:opacity-30 disabled:cursor-not-allowed"
              >
                <Check size={12} />
                <span className="text-[10px] font-mono-retro tracking-widest font-bold">APPLY</span>
              </button>
            </div>

            {/* 底部装饰线 */}
            <div className="absolute bottom-0 left-0 right-0 h-[1px] bg-gradient-to-r from-transparent via-stone-700/20 to-transparent" />
          </div>
        </div>
      )}

      <style>{`
        @keyframes scan {
          0% { top: 0%; opacity: 0; }
          10% { opacity: 1; }
          90% { opacity: 1; }
          100% { top: 100%; opacity: 0; }
        }
      `}</style>
    </div>
  );
};

// --- Helper Component for Infinite Attributes (Redesigned) ---
const AttributeRowInfinite: React.FC<{
  icon: React.ReactNode;
  label: string;
  cnLabel: string;
  value: number;
  highlightClass?: string;
}> = ({ icon, label, cnLabel, value, highlightClass }) => {
  const magnitude = value === 0 ? 0 : Math.floor(Math.log10(value));

  let tier = 0;
  let colorClass = 'text-stone-400 group-hover:text-white';
  let glowClass = '';

  if (magnitude >= 8) {
    tier = 3;
    colorClass = 'text-white';
    glowClass = 'drop-shadow-[0_0_15px_rgba(255,255,255,0.8)]';
  } else if (magnitude >= 4) {
    tier = 2;
    colorClass = 'text-white';
    glowClass = 'drop-shadow-[0_0_8px_rgba(255,255,255,0.4)]';
  } else if (magnitude >= 2) {
    tier = 1;
    colorClass = 'text-stone-200';
  }

  const formattedValue = new Intl.NumberFormat('en-US').format(value);
  const isLong = formattedValue.length > 8;
  const firstDigit = parseInt(value.toString()[0]);

  return (
    <div className="flex flex-col bg-white/[0.005] hover:bg-white/[0.02] border border-white/[0.02] hover:border-white/10 px-6 py-5 rounded-2xl gap-4 relative overflow-hidden group transition-all duration-500">
      <div className="flex items-center justify-between z-10">
        <div className="flex items-center gap-5">
          <div
            className={`transition-colors ${tier >= 2 ? 'text-white animate-pulse shadow-[0_0_10px_white]' : 'text-stone-500 group-hover:text-stone-300'}`}
          >
            {icon}
          </div>
          <div className="flex flex-col gap-0.5">
            <span className="text-lg font-light font-serif-sc text-stone-300 group-hover:text-white transition-colors tracking-[0.2em]">
              {cnLabel}
            </span>
            <span className="text-[9px] font-mono-retro text-stone-600 tracking-[0.4em] uppercase">{label}</span>
          </div>
        </div>

        <div className="flex items-baseline gap-3">
          {magnitude >= 9 && (
            <span className="text-[9px] font-mono-retro text-white/50 tracking-[0.2em] animate-pulse uppercase">
              OVERRIDE
            </span>
          )}
          <span
            className={`font-mono-retro font-thin tracking-tighter ${highlightClass || colorClass} ${glowClass} ${isLong ? 'text-3xl' : 'text-5xl'} transition-all duration-700`}
          >
            {formattedValue}
          </span>
        </div>
      </div>

      {/* Monochrome Minimal Power Level Indicator */}
      <div className="relative w-full h-[1px] bg-white/5 mt-1">
        <div
          className={`absolute left-0 top-0 h-full transition-all duration-1000 ease-out bg-white
            ${tier === 3 ? 'shadow-[0_0_12px_white]' : tier >= 2 ? 'shadow-[0_0_8px_white]' : 'opacity-40 group-hover:opacity-70'}`}
          style={{ width: `${Math.max(5, (firstDigit / 9) * 100)}%` }}
        >
          {/* Diamond at the end */}
          <div className="absolute right-0 top-1/2 -translate-y-1/2 w-1.5 h-1.5 bg-white rotate-45 shadow-[0_0_8px_white] opacity-80" />
        </div>
      </div>

      {/* Magnitude Dots Indicator - Minimalist */}
      {magnitude >= 2 && (
        <div className="absolute right-6 bottom-3 flex gap-[4px] opacity-20 group-hover:opacity-80 transition-opacity duration-500">
          {[...Array(Math.min(8, magnitude))].map((_, i) => (
            <div
              key={i}
              className={`w-1 h-1 rounded-full ${tier === 3 ? 'bg-white' : tier >= 2 ? 'bg-stone-200' : 'bg-stone-400'}`}
            />
          ))}
        </div>
      )}

      {tier === 3 && (
        <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/[0.02] to-transparent mix-blend-overlay pointer-events-none animate-pulse"></div>
      )}
    </div>
  );
};
