import { CornerDownRight, X } from 'lucide-react';
import React, { useEffect } from 'react';
import { renderRichText } from '../parser';
import { DialogueSegment } from '../types';

interface LogScreenProps {
  segments: DialogueSegment[];
  onClose: () => void;
  playSfx: () => void;
  onJumpToSegment?: (index: number) => void;
}

export const LogScreen: React.FC<LogScreenProps> = ({ segments, onClose, playSfx, onJumpToSegment }) => {
  useEffect(() => {
    playSfx();
  }, []);

  const handleClose = () => {
    playSfx();
    onClose();
  };

  return (
    <div className="game-modal absolute inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-md animate-in fade-in duration-300">
      <div className="relative w-full max-w-4xl h-[90%] md:h-[85%] glass-panel flex flex-col overflow-hidden rounded-xl border border-white/10 shadow-[0_20px_60px_rgba(0,0,0,0.8)]">
        {/* 背景光晕 */}
        <div className="absolute top-0 right-0 w-1/2 h-[200px] bg-[radial-gradient(ellipse_at_top_right,rgba(255,255,255,0.05),transparent_70%)] pointer-events-none" />

        {/* Header */}
        <div className="relative z-10 flex justify-between items-center px-8 py-5 border-b border-white/10 bg-gradient-to-b from-white/[0.03] to-transparent shrink-0">
          <div className="flex items-center gap-4">
            <div className="flex flex-col">
              <div className="flex items-center gap-2">
                <span className="w-1.5 h-1.5 rounded-full bg-white animate-pulse shadow-[0_0_8px_rgba(255,255,255,0.8)]" />
                <h2 className="font-serif-sc text-lg text-white tracking-[0.2em] font-medium drop-shadow-md">
                  RECORD_LOG
                </h2>
              </div>
              <span className="font-mono-retro text-[9px] text-stone-400 tracking-[0.4em] uppercase ml-3.5">
                entries: {segments.length.toString().padStart(4, '0')}
              </span>
            </div>
          </div>
          <button
            onClick={handleClose}
            className="w-8 h-8 flex items-center justify-center bg-white/5 border border-white/10 text-stone-400 hover:text-white hover:bg-white/15 hover:border-white/30 transition-all duration-300 cursor-pointer rounded-full group"
          >
            <X size={14} className="group-hover:rotate-90 transition-transform duration-300" />
          </button>
        </div>

        {/* Content */}
        <div className="flex-1 overflow-y-auto px-8 py-6 custom-scrollbar relative z-10">
          {segments.length === 0 && (
            <div className="flex flex-col items-center justify-center h-full text-stone-500 opacity-60">
              <span className="font-mono-retro text-sm tracking-[0.3em] mb-2">NO_RECORDS</span>
              <span className="font-serif-sc text-xs tracking-widest">暂无对话记录</span>
            </div>
          )}

          <div className="relative mx-auto max-w-3xl">
            {/* 时间线竖线 (高级细线) */}
            {segments.length > 0 && (
              <div className="absolute left-[5px] top-6 bottom-4 w-px bg-gradient-to-b from-transparent via-white/20 to-transparent" />
            )}

            <div className="space-y-4">
              {segments.map((segment, index) => (
                <div
                  key={segment.id}
                  className="group relative pl-8 py-3 rounded-lg hover:bg-white/[0.03] border border-transparent hover:border-white/5 transition-all duration-300 cursor-default"
                >
                  {/* 时间线发光圆点 */}
                  <div className="absolute left-[3px] top-5 w-[5px] h-[5px] rounded-full bg-stone-500 border border-black group-hover:bg-white group-hover:shadow-[0_0_8px_rgba(255,255,255,0.8)] transition-all duration-300" />

                  {/* 说话人与索引 */}
                  <div className="flex items-center justify-between mb-2">
                    <span className="font-serif-sc font-medium text-sm text-stone-400 group-hover:text-stone-200 transition-colors drop-shadow-sm">
                      {segment.speaker}
                    </span>
                    <span className="font-mono-retro text-[9px] text-stone-600 tracking-[0.2em] group-hover:text-stone-400 transition-colors">
                      MSG_#{String(index + 1).padStart(3, '0')}
                    </span>
                  </div>

                  {/* 内容 */}
                  <div className="flex items-start gap-4">
                    <p
                      className={`flex-1 font-serif-sc text-[15px] leading-[1.8] text-stone-300 drop-shadow-sm transition-colors ${segment.isInnerMonologue ? 'italic text-stone-400' : 'group-hover:text-white'}`}
                      dangerouslySetInnerHTML={{ __html: renderRichText(segment.text) }}
                    />
                    {onJumpToSegment && (
                      <button
                        onClick={() => {
                          playSfx();
                          onJumpToSegment(index);
                        }}
                        className="shrink-0 mt-1 p-2 rounded-full text-stone-600 hover:text-white hover:bg-white/10 opacity-0 group-hover:opacity-100 transition-all duration-300 cursor-pointer shadow-[0_0_10px_transparent] hover:shadow-[0_0_10px_rgba(255,255,255,0.1)] -translate-x-2 group-hover:translate-x-0"
                        title="JUMP_TO_ENTRY"
                      >
                        <CornerDownRight size={14} />
                      </button>
                    )}
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* 底部阅读渐变遮罩 */}
          <div className="sticky bottom-0 left-0 right-0 h-12 bg-gradient-to-t from-[rgba(10,10,12,0.95)] to-transparent pointer-events-none -mx-8 -mb-6" />
        </div>
      </div>
    </div>
  );
};
